@namespace Lumeo

<div class="@RootClasses" @attributes="AdditionalAttributes">
    <div class="flex items-center gap-2">
        @if (IconContent is not null)
        {
            <div class="flex h-8 w-8 items-center justify-center rounded-md bg-muted/60 text-muted-foreground">
                @IconContent
            </div>
        }
        @if (!string.IsNullOrEmpty(Label))
        {
            <div class="text-sm text-muted-foreground">@Label</div>
        }
    </div>

    <div class="mt-3 text-3xl font-semibold tracking-tight text-foreground">@Value</div>

    @if (Delta.HasValue || SparkContent is not null)
    {
        <div class="mt-3 flex items-center justify-between gap-2">
            @if (Delta.HasValue)
            {
                <Lumeo.Delta Value="Delta.Value"
                             Format="DeltaFormatValue"
                             Positive="DeltaPositiveValue" />
            }
            else
            {
                <span></span>
            }
            @if (SparkContent is not null)
            {
                <div class="flex-1 min-w-0" style="max-width: 140px">
                    @SparkContent
                </div>
            }
        </div>
    }
</div>

@code {
    /// <summary>Small caption shown next to the optional icon, above the value (e.g.
    /// "Revenue").</summary>
    [Parameter] public string? Label { get; set; }
    /// <summary>The headline metric, rendered large and bold (e.g. "$12,400"). Pre-formatted
    /// by the caller — this component does not format numbers.</summary>
    [Parameter] public string? Value { get; set; }
    /// <summary>Change amount rendered via <see cref="Lumeo.Delta"/> (e.g. +12.5). Omitted
    /// when null.</summary>
    [Parameter] public double? Delta { get; set; }
    /// <summary>How <see cref="Delta"/> is formatted: as a percentage (default) or an
    /// absolute number.</summary>
    [Parameter] public KpiDeltaFormat DeltaFormat { get; set; } = KpiDeltaFormat.Percent;
    /// <summary>Whether a positive <see cref="Delta"/> should be styled as good (default)
    /// or bad — e.g. for metrics where a rising value is undesirable (cost, churn).</summary>
    [Parameter] public KpiDeltaDirection DeltaPositive { get; set; } = KpiDeltaDirection.Good;
    /// <summary>Small icon rendered in a muted square badge next to <see cref="Label"/>.</summary>
    [Parameter] public RenderFragment? IconContent { get; set; }
    /// <summary>Sparkline or mini-chart rendered alongside the delta, capped at 140px wide.</summary>
    [Parameter] public RenderFragment? SparkContent { get; set; }
    /// <summary>Additional CSS classes merged onto the root <c>div</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the root <c>div</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string RootClasses =>
        Cx.Merge("rounded-xl border border-border/40 bg-card text-card-foreground p-5", Class);

    private Lumeo.Delta.DeltaFormat DeltaFormatValue =>
        DeltaFormat == KpiDeltaFormat.Absolute
            ? Lumeo.Delta.DeltaFormat.Absolute
            : Lumeo.Delta.DeltaFormat.Percent;

    private Lumeo.Delta.DeltaDirection DeltaPositiveValue =>
        DeltaPositive == KpiDeltaDirection.Bad
            ? Lumeo.Delta.DeltaDirection.Bad
            : Lumeo.Delta.DeltaDirection.Good;

    public enum KpiDeltaFormat { Percent, Absolute }
    public enum KpiDeltaDirection { Good, Bad }
}
